'use strict';
const path = require('path');

const LIB = require('../lib/jibo-cai-utils');
const TestUtils = LIB.TestUtils;

function dateDiffMs(date1, date2) {
  return date1 - date2;
}

function randomEqual(numberToCompare, id, ns) {
  let allSame = true;
  for (let i = 0; i < 500; i++) {
    let anotherRandom = TestUtils.getRandom(id, ns);
    if (anotherRandom !== numberToCompare) {
      allSame = false;
    }
  }
  return allSame;
}


describe('Test Utils', function() {
  this.timeout(5000);

  beforeEach( () => {
    TestUtils.enableTesting(false);
    TestUtils.clearAllTests();
  });

  it('Test mode not enabled: Date', () => {
    TestUtils.enableTesting(false);

    let realDate = new Date();
    let testDate = TestUtils.getDate();

    expect( Math.abs(dateDiffMs(realDate, testDate)) ).to.be.lessThan(100);
  });

  it('Test mode enabled enabled: Date', (done) => {
    TestUtils.enableTesting(true);

    let testDate = new Date(1999, 1, 10);
    TestUtils.setTestDate(testDate, 'id');
    let testDate1 = TestUtils.getDate('id');

    setTimeout( () => {
      let testDate2 = TestUtils.getDate('id');
      expect(dateDiffMs(testDate1, testDate2)).to.equal(0);
      let testDate3 = TestUtils.getDate();
      setTimeout( () => {
        let testDate4 = TestUtils.getDate();
        expect(dateDiffMs(testDate3, testDate4)).to.not.equal(0);
        done();
      }, 1000);
    }, 1000);
  });


  it('Test mode not enabled: Random', () => {
    let testRandom = TestUtils.getRandom();
    expect( randomEqual(testRandom) ).to.be.equal(false);

    testRandom = TestUtils.getRandom('someId');
    expect( randomEqual(testRandom, 'someId') ).to.be.equal(false);

    testRandom = TestUtils.getRandom('someId', 'someNs');
    expect( randomEqual(testRandom, 'someId', 'someNs') ).to.be.equal(false);
  });

  it('Test mode enabled: Random', () => {
    TestUtils.enableTesting(true);
    TestUtils.setTestRandom(0.2, 'someId');
    let testRandom = TestUtils.getRandom('someId');
    expect( randomEqual(testRandom, 'someId') ).to.be.equal(true);

    testRandom = TestUtils.getRandom('someId', 'someNs');
    expect( randomEqual(testRandom, 'someId', 'someNs') ).to.be.equal(false);

    TestUtils.setTestRandom(0.3, 'someId', 'someNs');
    testRandom = TestUtils.getRandom('someId', 'someNs');
    expect( randomEqual(testRandom, 'someId', 'someNs') ).to.be.equal(true);
 });

  it('Clearing namespaces', () => {
    TestUtils.enableTesting(true);
    let test1, test2;

    TestUtils.setTestRandom(0.2, 'someId');
    TestUtils.setTestRandom(0.3, 'someId', 'ns2');
    test1 = TestUtils.getRandom('someId');
    test2 = TestUtils.getRandom('someId', 'ns2');
    expect( randomEqual(test1, 'someId') ).to.equal( true );
    expect( randomEqual(test2, 'someId', 'ns2') ).to.equal( true );

    TestUtils.clearTests();
    expect( randomEqual(test1, 'someId') ).to.equal( false );
    expect( randomEqual(test2, 'someId', 'ns2') ).to.equal( true );

    TestUtils.clearTests('ns2');
    expect( randomEqual(test1, 'someId') ).to.equal( false );
    expect( randomEqual(test2, 'someId', 'ns2') ).to.equal( false );

    TestUtils.setTestRandom(0.4, 'someId');
    TestUtils.setTestRandom(0.5, 'someId', 'ns2');
    test1 = TestUtils.getRandom('someId');
    test2 = TestUtils.getRandom('someId', 'ns2');
    expect( randomEqual(test1, 'someId') ).to.equal( true );
    expect( randomEqual(test2, 'someId', 'ns2') ).to.equal( true );

    TestUtils.clearAllTests();
    expect( randomEqual(test1, 'someId') ).to.equal( false );
    expect( randomEqual(test2, 'someId', 'ns2') ).to.equal( false );
  });
});
